/**
 * Perform an active scan on all Zigbee channels to discover networks.
 */
static zigbee_error_t network_scan(zigbee_device_t *dev)
{
    printf("\n[NETWORK] Starting active scan on channels %d-%d...\n",
           ZIGBEE_CHANNEL_MIN, ZIGBEE_CHANNEL_MAX);

    dev->network_state = NETWORK_STATE_SCANNING;
    dev->scan_results.count = 0;

    hal_led_blink(3, 200); /* Visual indication: scanning */

    /* Scan each channel */
    for (uint8_t ch = ZIGBEE_CHANNEL_MIN; ch <= ZIGBEE_CHANNEL_MAX; ch++) {
        hal_radio_set_channel(ch);
        hal_delay_ms(30 * (1 << ZIGBEE_SCAN_DURATION)); /* aBaseSuperframeDuration * 2^scanDuration */

        /*
         * In real firmware, we would send beacon requests and collect
         * beacon responses. Here we simulate finding a network.
         */
        hal_watchdog_feed();
    }

    /* Simulate finding a suitable network */
    if (dev->scan_results.count == 0) {
        /* Simulate discovery of one network for demonstration */
        network_beacon_t *beacon = &dev->scan_results.beacons[0];
        beacon->pan_id = 0x1A2B;
        beacon->channel = ZIGBEE_DEFAULT_CHANNEL;
        memset(beacon->extended_pan_id, 0x00, ZIGBEE_EUI64_SIZE);
        beacon->extended_pan_id[0] = 0xDE;
        beacon->extended_pan_id[1] = 0xAD;
        beacon->extended_pan_id[6] = 0xBE;
        beacon->extended_pan_id[7] = 0xEF;
        beacon->lqi = 200;
        beacon->rssi = -45;
        beacon->permit_joining = true;
        beacon->has_trust_center = true;
        beacon->stack_profile = 2;   /* Zigbee PRO */
        beacon->zigbee_version = 3;
        dev->scan_results.count = 1;

        printf("[NETWORK] Found network: PAN=0x%04X, CH=%d, LQI=%d, RSSI=%d, PermitJoin=%s\n",
               beacon->pan_id, beacon->channel, beacon->lqi, beacon->rssi,
               beacon->permit_joining ? "YES" : "NO");
    }

    if (dev->scan_results.count == 0) {
        printf("[NETWORK] No networks found\n");
        dev->network_state = NETWORK_STATE_IDLE;
        return ZB_ERR_NO_NETWORK;
    }

    printf("[NETWORK] Scan complete. Found %d network(s)\n", dev->scan_results.count);
    return ZB_SUCCESS;
}

/**
 * Select the best network from scan results.
 * Criteria: permit joining enabled, best LQI, has trust center.
 */
static int network_select_best(const network_scan_result_t *results)
{
    int best_idx = -1;
    uint8_t best_lqi = 0;

    for (uint8_t i = 0; i < results->count; i++) {
        const network_beacon_t *b = &results->beacons[i];

        /* Must have permit joining enabled */
        if (!b->permit_joining) {
            printf("[NETWORK] Skipping PAN 0x%04X (permit join closed)\n", b->pan_id);
            continue;
        }

        /* Must be Zigbee PRO stack profile */
        if (b->stack_profile != 2) {
            printf("[NETWORK] Skipping PAN 0x%04X (not Zigbee PRO)\n", b->pan_id);
            continue;
        }

        /* Must have a trust center */
        if (!b->has_trust_center) {
            printf("[NETWORK] Skipping PAN 0x%04X (no trust center)\n", b->pan_id);
            continue;
        }

        /* Select best LQI */
        if (b->lqi > best_lqi) {
            best_lqi = b->lqi;
            best_idx = (int)i;
        }
    }

    return best_idx;
}

