/**
 * Send an Association Request to join the selected network.
 */
static zigbee_error_t network_send_association_request(zigbee_device_t *dev,
                                                        const network_beacon_t *target)
{
    printf("[NETWORK] Sending Association Request to PAN 0x%04X on channel %d\n",
           target->pan_id, target->channel);

    /* Configure radio for the target network */
    hal_radio_set_channel(target->channel);
    hal_radio_set_pan_id(target->pan_id);

    /*
     * Build and send MAC Association Request frame.
     * Capability info: Allocate address, receiver on when idle, mains powered.
     */
    uint8_t assoc_request[32];
    uint8_t len = 0;

    /* Frame Control (Association Request) */
    assoc_request[len++] = 0x23; /* Command frame, ack request */
    assoc_request[len++] = 0xC8; /* Extended addressing */

    /* Sequence number */
    assoc_request[len++] = (uint8_t)(hal_get_random() & 0xFF);

    /* Destination PAN ID */
    assoc_request[len++] = (uint8_t)(target->pan_id & 0xFF);
    assoc_request[len++] = (uint8_t)((target->pan_id >> 8) & 0xFF);

    /* Coordinator address (0x0000) */
    assoc_request[len++] = 0x00;
    assoc_request[len++] = 0x00;

    /* Source PAN ID (0xFFFF for association) */
    assoc_request[len++] = 0xFF;
    assoc_request[len++] = 0xFF;

    /* Source EUI-64 */
    memcpy(&assoc_request[len], dev->config.eui64, ZIGBEE_EUI64_SIZE);
    len += ZIGBEE_EUI64_SIZE;

    /* Capability Information */
    uint8_t capability = 0x00;
    capability |= 0x04;  /* Receiver on when idle (mains powered) */
    capability |= 0x08;  /* Mains powered */
    capability |= 0x40;  /* Allocate short address */
    if (dev->config.device_type == DEVICE_TYPE_ROUTER) {
        capability |= 0x02;  /* FFD (Full Function Device) - router capable */
    }
    assoc_request[len++] = capability;

    /* Command ID: Association Request */
    assoc_request[len++] = 0x01;

    hal_radio_tx(assoc_request, len);

    printf("[NETWORK] Association Request sent (capability=0x%02X)\n", capability);
    return ZB_SUCCESS;
}

/**
 * Process Association Response from the coordinator/router.
 * Simulates receiving a short address assignment.
 */
static zigbee_error_t network_process_association_response(zigbee_device_t *dev)
{
    printf("[NETWORK] Waiting for Association Response...\n");
    hal_delay_ms(500);

    /* Simulate successful association with assigned short address */
    uint16_t assigned_address = (uint16_t)(hal_get_random() & 0xFFFE) | 0x0001;
    dev->config.short_address = assigned_address;

    hal_radio_set_short_address(assigned_address);
    printf("[NETWORK] Association successful! Assigned short address: 0x%04X\n",
           assigned_address);

    return ZB_SUCCESS;
}

/**
 * Authenticate with the Trust Center using the pre-shared link key.
 * The TC will send us the network key encrypted with our link key.
 */
static zigbee_error_t network_authenticate_with_trust_center(zigbee_device_t *dev)
{
    printf("\n[NETWORK] Authenticating with Trust Center...\n");

    dev->commission_state = COMMISSION_STATE_LINK_KEY_DERIVED;

    if (!dev->security.tc_link_key.is_valid) {
        printf("[NETWORK] ERROR: No valid Trust Center link key\n");
        dev->commission_state = COMMISSION_STATE_FAILED;
        return ZB_ERR_AUTH_FAILED;
    }

    printf("[NETWORK] Using %s link key for authentication\n",
           dev->security.tc_link_key.is_global ? "HA Global" : "Install Code derived");

    /*
     * In the actual Zigbee stack:
     * 1. The joining device sends an unsecured Update Device to the TC
     * 2. The TC verifies our link key and sends a Transport Key command
     *    containing the network key, encrypted with our link key
     * 3. We decrypt the network key and can now communicate securely
     */

    /* Simulate receiving Transport Key from TC */
    hal_delay_ms(200);

    /* Simulated encrypted network key from TC */
    uint8_t encrypted_nwk_key[ZIGBEE_NETWORK_KEY_SIZE] = {
        0xAB, 0xCD, 0xEF, 0x01, 0x23, 0x45, 0x67, 0x89,
        0x9A, 0xBC, 0xDE, 0xF0, 0x12, 0x34, 0x56, 0x78
    };

    zigbee_error_t err = security_process_tc_transport_key(&dev->security,
                                                            encrypted_nwk_key, 0);
    if (err != ZB_SUCCESS) {
        printf("[NETWORK] Trust Center authentication FAILED\n");
        dev->commission_state = COMMISSION_STATE_FAILED;
        return err;
    }

    dev->commission_state = COMMISSION_STATE_TC_AUTHENTICATED;
    printf("[NETWORK] Trust Center authentication SUCCESSFUL\n");

    /* Send a secured Device Announce to the network */
    printf("[NETWORK] Sending Device Announce broadcast\n");
    uint8_t device_announce[32];
    uint8_t len = 0;

    /* ZDO Device Announce header (simplified) */
    device_announce[len++] = 0x00; /* Transaction seq */
    device_announce[len++] = (uint8_t)(dev->config.short_address & 0xFF);
    device_announce[len++] = (uint8_t)((dev->config.short_address >> 8) & 0xFF);
    memcpy(&device_announce[len], dev->config.eui64, ZIGBEE_EUI64_SIZE);
    len += ZIGBEE_EUI64_SIZE;
    device_announce[len++] = 0x8C; /* Capability: rx on, mains, allocate addr */

    hal_radio_tx(device_announce, len);

    return ZB_SUCCESS;
}

/**
 * Complete network joining procedure.
 */
static zigbee_error_t network_join(zigbee_device_t *dev)
{
    zigbee_error_t err;

    printf("\n========================================\n");
    printf("  ZIGBEE NETWORK JOIN PROCEDURE START\n");
    printf("========================================\n\n");

    /* Step 1: Scan for available networks */
    err = network_scan(dev);
    if (err != ZB_SUCCESS) {
        printf("[JOIN] No networks available\n");
        hal_led_blink(5, 500); /* Error indication */
        return err;
    }

    /* Step 2: Select the best network */
    int best = network_select_best(&dev->scan_results);
    if (best < 0) {
        printf("[JOIN] No suitable network found (none with permit join open)\n");
        hal_led_blink(5, 500);
        return ZB_ERR_PERMIT_JOIN_DENIED;
    }

    const network_beacon_t *target = &dev->scan_results.beacons[best];
    printf("\n[JOIN] Selected network: PAN=0x%04X, CH=%d, LQI=%d\n",
           target->pan_id, target->channel, target->lqi);

    dev->config.pan_id = target->pan_id;
    dev->config.channel = target->channel;

    /* Step 3: Send Association Request */
    dev->network_state = NETWORK_STATE_JOINING;
    err = network_send_association_request(dev, target);
    if (err != ZB_SUCCESS) {
        return err;
    }

    /* Step 4: Process Association Response */
    err = network_process_association_response(dev);
    if (err != ZB_SUCCESS) {
        printf("[JOIN] Association failed\n");
        dev->network_state = NETWORK_STATE_ERROR;
        return err;
    }

    /* Step 5: Authenticate with Trust Center */
    dev->network_state = NETWORK_STATE_AUTHENTICATING;
    err = network_authenticate_with_trust_center(dev);
    if (err != ZB_SUCCESS) {
        printf("[JOIN] Trust Center authentication failed\n");
        dev->network_state = NETWORK_STATE_ERROR;
        return err;
    }

    /* Step 6: Mark as connected */
    dev->network_state = NETWORK_STATE_CONNECTED;
    dev->commission_state = COMMISSION_STATE_NETWORK_KEY_RECEIVED;

    /* Save network parameters and security keys to NVM */
    security_save_to_nvm(&dev->security);
    hal_nvm_write(0x3000, &dev->config, sizeof(device_config_t));

    printf("\n[JOIN] *** NETWORK JOIN COMPLETE ***\n");
    printf("[JOIN] PAN ID: 0x%04X\n", dev->config.pan_id);
    printf("[JOIN] Channel: %d\n", dev->config.channel);
    printf("[JOIN] Short Address: 0x%04X\n", dev->config.short_address);
    printf("[JOIN] EUI-64: ");
    print_eui64(dev->config.eui64);
    printf("\n\n");

    hal_led_set(true); /* Solid LED = connected */

    return ZB_SUCCESS;
}

/**
 * Network join with retries for robustness.
 */
static zigbee_error_t network_join_with_retries(zigbee_device_t *dev)
{
    zigbee_error_t err;

    for (uint8_t attempt = 1; attempt <= ZIGBEE_MAX_RETRIES; attempt++) {
        printf("[JOIN] Attempt %d of %d\n", attempt, ZIGBEE_MAX_RETRIES);
        dev->join_retries = attempt;

        err = network_join(dev);
        if (err == ZB_SUCCESS) {
            return ZB_SUCCESS;
        }

        printf("[JOIN] Attempt %d failed (error %d), waiting before retry...\n",
               attempt, err);

        /* Exponential backoff */
        uint32_t backoff_ms = 1000 * (1 << (attempt - 1));
        backoff_ms += hal_get_random() % 1000; /* Add jitter */
        printf("[JOIN] Waiting %u ms before next attempt\n", backoff_ms);
        hal_delay_ms(backoff_ms);
    }

    printf("[JOIN] All join attempts exhausted\n");
    return ZB_ERR_JOIN_FAILED;
}

/* ============================================================
 * Permit Join Management
 * When this device acts as a router, it can relay permit join
 * to help add more devices to the network.
 * ============================================================ */

/**
 * Open permit join on this device (if it's a router).
 * This allows new devices to join through this node.
 */
static zigbee_error_t permit_join_open(zigbee_device_t *dev, uint8_t duration_seconds)
{
    if (dev->network_state != NETWORK_STATE_CONNECTED) {
        printf("[PERMIT_JOIN] ERROR: Not connected to a network\n");
        return ZB_ERR_NO_NETWORK;
    }

    if (dev->config.device_type == DEVICE_TYPE_END_DEVICE) {
        printf("[PERMIT_JOIN] End devices cannot open permit join\n");
        return ZB_ERR_PERMIT_JOIN_DENIED;
    }

    printf("[PERMIT_JOIN] Opening permit join for %d seconds\n",
           duration_seconds == 254 ? 254 : duration_seconds);

    dev->network_state = NETWORK_STATE_PERMIT_JOIN_OPEN;

    /* Send Mgmt_Permit_Joining_req (ZDO cluster 0x0036) */
    uint8_t permit_join_cmd[8];
    uint8_t len = 0;

    permit_join_cmd[len++] = 0x00; /* Transaction sequence */
    permit_join_cmd[len++] = duration_seconds;
    permit_join_cmd[len++] = 0x01; /* TC significance: 1 = update TC */

    hal_radio_tx(permit_join_cmd, len);

    hal_led_blink(2, 300); /* Visual indication: permit join open */

    printf("[PERMIT_JOIN] Permit join is now OPEN\n");
    printf("[PERMIT_JOIN] New devices can join through this node\n");

    return ZB_SUCCESS;
}

/**
 * Close permit join on this device.
 */
static zigbee_error_t permit_join_close(zigbee_device_t *dev)
{
    if (dev->network_state == NETWORK_STATE_PERMIT_JOIN_OPEN) {
        printf("[PERMIT_JOIN] Closing permit join\n");
        dev->network_state = NETWORK_STATE_CONNECTED;

        uint8_t permit_join_cmd[4];
        uint8_t len = 0;
        permit_join_cmd[len++] = 0x00;
        permit_join_cmd[len++] = 0x00; /* Duration 0 = close */
        permit_join_cmd[len++] = 0x01;

        hal_radio_tx(permit_join_cmd, len);
        printf("[PERMIT_JOIN] Permit join is now CLOSED\n");
    }

    return ZB_SUCCESS;
}

/**
 * Request the coordinator to open permit join on the entire network.
 * This is typically triggered by user action (e.g., button press).
 */
static zigbee_error_t permit_join_request_network_wide(zigbee_device_t *dev,
                                                        uint8_t duration_seconds)
{
    if (dev->network_state != NETWORK_STATE_CONNECTED &&
        dev->network_state != NETWORK_STATE_PERMIT_JOIN_OPEN) {
        printf("[PERMIT_JOIN] ERROR: Not connected to a network\n");
        return ZB_ERR_NO_NETWORK;
    }

    printf("[PERMIT_JOIN] Requesting network-wide permit join for %d seconds\n",
           duration_seconds);

    /* Send broadcast Mgmt_Permit_Joining_req to 0xFFFC (all routers) */
    uint8_t cmd[8];
    uint8_t len = 0;

    cmd[len++] = 0x00; /* Transaction sequence */
    cmd[len++] = duration_seconds;
    cmd[len++] = 0x01; /* TC significance */

    /* In real firmware, this would be addressed to broadcast 0xFFFC */
    hal_radio_tx(cmd, len);

    printf("[PERMIT_JOIN] Network-wide permit join request sent\n");

    return ZB_SUCCESS;
}

/* ============================================================
 * Network Leave
 * ============================================================ */

static zigbee_error_t network_leave(zigbee_device_t *dev)
{
    if (dev->network_state == NETWORK_STATE_IDLE) {
        return ZB_SUCCESS;
    }

    printf("[NETWORK] Leaving network PAN 0x%04X\n", dev->config.pan_id);

    dev->network_state = NETWORK_STATE_LEAVING;

    /* Send Leave Request */
    uint8_t leave_cmd[16];
    uint8_t len = 0;
    leave_cmd[len++] = 0x00; /* Transaction seq */
    memcpy(&leave_cmd[len], dev->config.eui64, ZIGBEE_EUI64_SIZE);
    len += ZIGBEE_EUI64_SIZE;
    leave_cmd[len++] = 0x00; /* No rejoin, no remove children */

    hal_radio_tx(leave_cmd, len);

    /* Clear network state */
    dev->config.short_address = 0xFFFE;
    dev->config.pan_id = 0xFFFF;
    dev->network_state = NETWORK_STATE_IDLE;

    printf("[NETWORK] Left network successfully\n");

    return ZB_SUCCESS;
}

/* ============================================================
 * Smart Light Bulb Application Layer
 * ZCL On/Off Cluster (0x0006) and Level Control (0x0008)
 * ============================================================ */

static void light_bulb_init(light_bulb_t *light)
{
    light->state = LIGHT_OFF;
    light->brightness = 254;      /* Full brightness default */
    light->color_temp = 370;      /* ~2700K warm white */
    light->hue = 0;
    light->saturation = 0;
    light->is_commissioned = false;

    hal_led_set(false);
    printf("[LIGHT] Light bulb initialized (OFF, brightness=%d)\n", light->brightness);
}

static void light_bulb_on(light_bulb_t *light)
{
    light->state = LIGHT_ON;
    hal_led_set(true);
    printf("[LIGHT] Light turned ON (brightness=%d)\n", light->brightness);
}

static void light_bulb_off(light_bulb_t *light)
{
    light->state = LIGHT_OFF;
    hal_led_set(false);
    printf("[LIGHT] Light turned OFF\n");
}

static void light_bulb_toggle(light_bulb_t *light)
{
    if (light->state == LIGHT_ON) {
        light_bulb_off(light);
    } else {
        light_bulb_on(light);
    }
}

static void light_bulb_set_brightness(light_bulb_t *light, uint8_t level)
{
    if (level > 254) level = 254;
    light->brightness = level;
    printf("[LIGHT] Brightness set to %d (%.0f%%)\n",
           level, (level / 254.0) * 100.0);

    if (level == 0) {
        light_bulb_off(light);
    } else if (light->state == LIGHT_OFF) {
        light_bulb_on(light);
    }
}

/**
 * Process incoming ZCL commands for the light bulb.
 */
static void light_process_zcl_command(zigbee_device_t *dev,
                                       uint16_t cluster_id,
                                       uint8_t command_id,
                                       const uint8_t *payload,
                                       uint8_t payload_len)
{
    (void)payload_len;

    switch (cluster_id) {
        case 0x0006: /* On/Off Cluster */
            switch (command_id) {
                case 0x00: /* Off */
                    light_bulb_off(&dev->light);
                    break;
                case 0x01: /* On */
                    light_bulb_on(&dev->light);
                    break;
                case 0x02: /* Toggle */
                    light_bulb_toggle(&dev->light);
                    break;
                default:
                    printf("[LIGHT] Unknown On/Off command: 0x%02X\n", command_id);
                    break;
            }
            break;

        case 0x0008: /* Level Control Cluster */
            switch (command_id) {
                case 0x00: /* Move to Level */
                    if (payload_len >= 1) {
                        light_bulb_set_brightness(&dev->light, payload[0]);
                    }
                    break;
                case 0x04: /* Move to Level (with On/Off) */
                    if (payload_len >= 1) {
                        light_bulb_set_brightness(&dev->light, payload[0]);
                    }
                    break;
                default:
                    printf("[LIGHT] Unknown Level command: 0x%02X\n", command_id);
                    break;
            }
            break;

        default:
            printf("[LIGHT] Unknown cluster: 0x%04X\n", cluster_id);
            break;
    }
}

/**
 * Register ZCL endpoints and clusters for the light bulb.
 */
static void light_register_endpoints(zigbee_device_t *dev)
{
    printf("[LIGHT] Registering ZCL endpoints and clusters\n");

    dev->config.endpoint = 1;
    dev->config.profile_id = 0x0104;  /* Home Automation Profile */
    dev->config.device_id = 0x0101;   /* Dimmable Light */
    dev->config.manufacturer_code = 0x1234; /* Custom manufacturer code */

    printf("[LIGHT] Endpoint %d registered:\n", dev->config.endpoint);
    printf("  Profile: 0x%04X (Home Automation)\n", dev->config.profile_id);
    printf("  Device:  0x%04X (Dimmable Light)\n", dev->config.device_id);
    printf("  Server Clusters: On/Off (0x0006), Level Control (0x0008)\n");
    printf("  Server Clusters: Basic (0x0000), Identify (0x0003)\n");
}

/* ============================================================
 * Commissioning Workflow
 * Consumer-friendly installation sequence
 * ============================================================ */

/**
 * Entry point for the commissioning (touchlink or classical join).
 * For consumer-friendly setup:
 * 1. User screws in the bulb and powers it on
 * 2. Bulb automatically scans for open networks
 * 3. Joins and authenticates with the Trust Center
 * 4. Reports its endpoints to the coordinator
 * 5. Blinks to confirm successful commissioning
 */
static zigbee_error_t commissioning_start(zigbee_device_t *dev)
{
    zigbee_error_t err;

    printf("\n╔══════════════════════════════════════════╗\n");
    printf("║  SMART LIGHT BULB COMMISSIONING START    ║\n");
    printf("╚══════════════════════════════════════════╝\n\n");

    dev->commission_state = COMMISSION_STATE_IDLE;

    /* Initialize security (set up link key) */
    err = security_init(&dev->security);
    if (err != ZB_SUCCESS) {
        printf("[COMMISSION] Security initialization failed\n");
        dev->commission_state = COMMISSION_STATE_FAILED;
        return err;
    }
    dev->commission_state = COMMISSION_STATE_INSTALL_CODE_SET;

    /* Attempt to join a network */
    err = network_join_with_retries(dev);
    if (err != ZB_SUCCESS) {
        printf("[COMMISSION] Failed to join any network\n");
        dev->commission_state = COMMISSION_STATE_FAILED;

        /* Enter "searchlight" mode - blink slowly to indicate
           the bulb is looking for a network */
        printf("[COMMISSION] Entering search mode (blinking slowly)\n");
        hal_led_blink(0, 2000); /* Continuous slow blink */
        return err;
    }

    /* Register ZCL endpoints */
    light_register_endpoints(dev);

    /* If device is a router, open permit join briefly to help
       mesh formation during initial setup */
    if (dev->config.device_type == DEVICE_TYPE_ROUTER) {
        printf("[COMMISSION] Opening permit join for mesh expansion\n");
        permit_join_open(dev, ZIGBEE_PERMIT_JOIN_DURATION);
    }

    /* Mark commissioning as complete */
    dev->commission_state = COMMISSION_STATE_COMMISSIONED;
    dev->light.is_commissioned = true;

    /* Signal successful commissioning to user */
    printf("\n[COMMISSION] *** COMMISSIONING COMPLETE! ***\n");
    printf("[COMMISSION] Blinking light to confirm success\n");
    hal_led_blink(5, 200);  /* Quick blinks = success */
    hal_delay_ms(1500);

    /* Turn on the light to show it's working */
    light_bulb_on(&dev->light);

    return ZB_SUCCESS;
}

/* ============================================================
 * Factory Reset
 * ============================================================ */

static void factory_reset(zigbee_device_t *dev)
{
    printf("\n[RESET] *** FACTORY RESET ***\n");

    /* Leave the current network if connected */
    if (dev->network_state != NETWORK_STATE_IDLE) {
        network_leave(dev);
    }

    /* Clear all security material */
    security_clear(&dev->security);

    /* Reset device configuration */
    dev->config.short_address = 0xFFFE;
    dev->config.pan_id = 0xFFFF;
    dev->config.channel = 0;
    dev->network_state = NETWORK_STATE_IDLE;
    dev->commission_state = COMMISSION_STATE_IDLE;
    dev->join_retries = 0;

    /* Reset light state */
    light_bulb_init(&dev->light);

    /* Clear NVM */
    uint8_t zeros[64] = {0};
    hal_nvm_write(0x2000, zeros, 64);
    hal_nvm_write(0x3000, zeros, 64);

    printf("[RESET] Factory reset complete\n");
    printf("[RESET] Device will restart commissioning\n\n");
}

/* ============================================================
 * Device Initialization
 * ============================================================ */

static void device_init(zigbee_device_t *dev)
{
    printf("\n╔══════════════════════════════════════════╗\n");
    printf("║    ZIGBEE SMART LIGHT BULB v1.0          ║\n");
    printf("║    Initializing...                       ║\n");
    printf("╚══════════════════════════════════════════╝\n\n");

    memset(dev, 0, sizeof(zigbee_device_t));

    /* Initialize hardware */
    hal_radio_init();

    /* Get device EUI-64 */
    hal_get_eui64(dev->config.eui64);
    printf("[INIT] Device EUI-64: ");
    print_eui64(dev->config.eui64);
    printf("\n");

    /* Set device type - light bulbs are typically routers
       (mains powered, always on) to help extend the mesh */
    dev->config.device_type = DEVICE_TYPE_ROUTER;
    printf("[INIT] Device type: Router (mains-powered light bulb)\n");

    /* Initialize defaults */
    dev->config.short_address = 0xFFFE;  /* Not assigned yet */
    dev->config.pan_id = 0xFFFF;         /* Not joined yet */
    dev->network_state = NETWORK_STATE_IDLE;
    dev->commission_state = COMMISSION_STATE_IDLE;
    dev->join_retries = 0;
    dev->factory_reset_pending = false;

    /* Initialize light bulb */
    light_bulb_init(&dev->light);

    printf("[INIT] Initialization complete\n");
}

/**
 * Check if we have a previously saved network configuration.
 * If so, try to rejoin directly without full commissioning.
 */
static bool device_check_saved_network(zigbee_device_t *dev)
{
    device_config_t saved_config;
    hal_nvm_read(0x3000, &saved_config, sizeof(device_config_t));

    if (saved_config.pan_id != 0xFFFF && saved_config.pan_id != 0x0000) {
        printf("[INIT] Found saved network config: PAN=0x%04X, CH=%d, Addr=0x%04X\n",
               saved_config.pan_id, saved_config.channel, saved_config.short_address);

        /* Restore configuration */
        dev->config.pan_id = saved_config.pan_id;
        dev->config.channel = saved_config.channel;
        dev->config.short_address = saved_config.short_address;

        /* Restore security keys */
        hal_nvm_read(0x2000, &dev->security.network_key, sizeof(network_key_t));
        hal_nvm_read(0x2100, &dev->security.tc_link_key, sizeof(trust_center_link_key_t));

        return true;
    }

    printf("[INIT] No saved network configuration found\n");
    return false;
}

/**
 * Rejoin the previously saved network (e.g., after power cycle).
 */
static zigbee_error_t device_rejoin_network(zigbee_device_t *dev)
{
    printf("[REJOIN] Attempting to rejoin saved network...\n");

    hal_radio_set_channel(dev->config.channel);
    hal_radio_set_pan_id(dev->config.pan_id);
    hal_radio_set_short_address(dev->config.short_address);

    if (dev->security.network_key.is_valid) {
        printf("[REJOIN] Using saved network key (seq=%d)\n",
               dev->security.network_key.sequence_number);

        /* Send a secured NWK Rejoin Request */
        uint8_t rejoin_cmd[16];
        uint8_t len = 0;
        rejoin_cmd[len++] = 0x06; /* NWK Command: Rejoin Request */
        rejoin_cmd[len++] = 0x8C; /* Capability */
        hal_radio_tx(rejoin_cmd, len);

        /* Simulate successful rejoin */
        hal_delay_ms(200);
        dev->network_state = NETWORK_STATE_CONNECTED;
        dev->commission_state = COMMISSION_STATE_COMMISSIONED;
        dev->light.is_commissioned = true;

        printf("[REJOIN] Successfully rejoined network\n");

        /* Register endpoints again */
        light_register_endpoints(dev);

        /* Restore light to previous state */
        light_bulb_on(&dev->light);

        return ZB_SUCCESS;
    }

    printf("[REJOIN] No valid network key, need full commissioning\n");
    return ZB_ERR_AUTH_FAILED;
}

/* ============================================================
 * Main Event Loop
 * ============================================================ */

/**
 * Process periodic tasks.
 */
static void device_tick(zigbee_device_t *dev)
{
    dev->uptime_seconds++;
    hal_watchdog_feed();

    /* Check for factory reset (e.g., power cycle 5 times) */
    if (dev->factory_reset_pending) {
        factory_reset(dev);
        dev->factory_reset_pending = false;
        commissioning_start(dev);
    }

    /* If permit join is open and we're a router, check timeout */
    if (dev->network_state == NETWORK_STATE_PERMIT_JOIN_OPEN) {
        /* In real firmware, this would use a timer */
        /* After timeout, close permit join automatically */
    }

    /* Simulate receiving a ZCL command every 10 seconds for demo */
    if (dev->light.is_commissioned && (dev->uptime_seconds % 10 == 0)) {
        uint8_t toggle_payload[] = {};
        light_process_zcl_command(dev, 0x0006, 0x02, toggle_payload, 0);
    }
}

/* ============================================================
 * Main Entry Point
 * ============================================================ */

int main(void)
{
    zigbee_error_t err;

    /* Initialize device */
    device_init(&g_device);

    /* Check if we have a saved network to rejoin */
    if (device_check_saved_network(&g_device)) {
        err = device_rejoin_network(&g_device);
        if (err == ZB_SUCCESS) {
            printf("\n[MAIN] Device rejoined previous network successfully\n");
            goto main_loop;
        }
        printf("[MAIN] Rejoin failed, starting fresh commissioning\n");
    }

    /* Start fresh commissioning (first-time setup) */
    err = commissioning_start(&g_device);
    if (err != ZB_SUCCESS) {
        printf("[MAIN] Commissioning failed (error %d)\n", err);
        printf("[MAIN] Device will retry periodically...\n");

        /* In production, we'd enter a low-power retry loop */
        for (int retry = 0; retry < 3; retry++) {
            hal_delay_ms(30000); /* Wait 30 seconds */
            err = commissioning_start(&g_device);
            if (err == ZB_SUCCESS) break;
        }

        if (err != ZB_SUCCESS) {
            printf("[MAIN] All commissioning attempts failed\n");
            printf("[MAIN] Power cycle the device near a coordinator with permit join open\n");
            return 1;
        }
    }

main_loop:
    printf("\n╔══════════════════════════════════════════╗\n");
    printf("║  SMART LIGHT BULB IS READY!              ║\n");
    printf("║  Network: PAN 0x%04X, CH %2d              ║\n",
           g_device.config.pan_id, g_device.config.channel);
    printf("║  Address: 0x%04X                          ║\n",
           g_device.config.short_address);
    printf("╚══════════════════════════════════════════╝\n\n");

    /* Main event loop */
    printf("[MAIN] Entering main event loop\n");
    for (int cycle = 0; cycle < 30; cycle++) {
        device_tick(&g_device);
        hal_delay_ms(1000);

        /* Demonstrate some functionality */
        if (cycle == 5) {
            printf("\n--- Demo: Remote command to set brightness to 50%% ---\n");
            uint8_t level_payload[] = { 127, 0x00, 0x0A }; /* Level, transition time */
            light_process_zcl_command(&g_device, 0x0008, 0x04,
                                      level_payload, sizeof(level_payload));
        }

        if (cycle == 10 && g_device.config.device_type == DEVICE_TYPE_ROUTER) {
            printf("\n--- Demo: Opening permit join for adding more devices ---\n");
            permit_join_open(&g_device, ZIGBEE_PERMIT_JOIN_DURATION);
        }

        if (cycle == 15) {
            printf("\n--- Demo: Remote toggle command ---\n");
            light_process_zcl_command(&g_device, 0x0006, 0x02, NULL, 0);
        }

        if (cycle == 20 && g_device.network_state == NETWORK_STATE_PERMIT_JOIN_OPEN) {
            printf("\n--- Demo: Closing permit join ---\n");
            permit_join_close(&g_device);
        }
    }

    /* Demonstrate factory reset */
    printf("\n--- Demo: Factory Reset ---\n");
    factory_reset(&g_device);

    printf("\n[MAIN] Demo complete. In production, the event loop runs forever.\n");

    return 0;
}